<template>
  <div class="status-panel" v-if="data">
    <!-- ═══ 聚会状态 Hero ═══ -->
    <div class="hero-banner" :class="{ 'hero-active': data.俱乐部.当前聚会.状态 === '进行中' }">
      <div class="hero-bg"></div>
      <div class="hero-content">
        <template v-if="data.俱乐部.当前聚会.状态 === '未开始'">
          <div class="hero-idle">
            <div class="hero-icon">🌙</div>
            <div class="hero-title">自毁俱乐部</div>
            <div class="hero-subtitle">休眠中 · 等待下一次聚会</div>
            <button class="btn btn-hero" @click="startSession">📍 开始聚会</button>
          </div>
        </template>
        <template v-else>
          <div class="hero-live">
            <div class="hero-live-indicator">
              <span class="hero-dot" />
              <span class="hero-live-text">LIVE</span>
            </div>
            <div class="hero-title">
              聚会 <strong>{{ data.俱乐部.当前聚会.编号 }}</strong>
            </div>
            <div class="hero-subtitle" v-if="data.俱乐部.当前聚会.主题">
              {{ data.俱乐部.当前聚会.主题 }}
            </div>
            <div class="hero-actions">
              <button class="btn btn-photo" @click="takePhoto" :disabled="isProcessing">{{ isProcessing ? '⏳ 处理中...' : '📷 拍照' }}</button>
              <button class="btn btn-danger" @click="endSession" :disabled="isProcessing">🔚 结束聚会</button>
              <button class="btn" @click="syncAllTapes" :disabled="isProcessing" title="将所有磁带的 MVU 数据写回世界书">🔄 同步</button>
            </div>
          </div>
        </template>
      </div>
    </div>


    <!-- ═══ 磁带列表 ═══ -->
    <CollapsiblePanel title="📼 角色磁带" :default-open="true">
      <div v-if="!allTapes.length && !showForm" style="color: var(--text-muted); font-size: 11px;">
        尚未录入任何磁带
      </div>

      <!-- 已插入的磁带（enabled） -->
      <div v-for="tape in allTapes" :key="tape.代号"
           class="tape-card"
           :class="{
             'tape-disabled': !tape.已插入,
             'tape-unsync': tape.已插入 && data.磁带索引[tape.代号] && (data.磁带索引[tape.代号].聚会履历草稿 || data.磁带索引[tape.代号].待同步照片.length),
           }">
        <div class="tape-status-bar" :class="{
          'bar-active': tape.已插入 && data.磁带索引[tape.代号]?.状态 === '活跃',
          'bar-standby': tape.已插入 && data.磁带索引[tape.代号]?.状态 === '待命',
          'bar-away': tape.已插入 && data.磁带索引[tape.代号]?.状态 === '离场',
        }"></div>
        <div class="tape-body">
          <div class="tape-header">
            <span class="tape-codename">{{ tape.代号 }}</span>
            <div style="display: flex; align-items: center; gap: 4px;">
              <StatusBadge
                :label="tape.已插入 ? '已插入' : '未插入'"
                :type="tape.已插入 ? 'active' : 'idle'"
              />
              <button class="btn-icon" title="编辑磁带" @click="startEdit(tape.代号)">✏️</button>
              <button class="btn-icon" v-if="tape.已插入" title="同步磁带到世界书" @click="syncTape(tape.代号)">🔄</button>
              <button class="btn-icon" title="初始化磁带" @click="resetTarget = tape.代号">🗑️</button>
              <button
                class="btn-icon"
                :title="tape.已插入 ? '弹出磁带' : '插入磁带'"
                @click="toggleTape(tape.代号, !tape.已插入)"
              >
                {{ tape.已插入 ? '⏏️' : '📥' }}
              </button>
            </div>
          </div>
          <div class="tape-detail" v-if="tape.已插入 && data.磁带索引[tape.代号]">
            <ResourceBar label="真实度" :value="data.磁带索引[tape.代号].真实度" :max="100" unit="%" />
            <div class="tape-sync-info" v-if="data.磁带索引[tape.代号].聚会履历草稿 || data.磁带索引[tape.代号].待同步照片.length">
              <span class="sync-badge">📝 有未同步数据</span>
            </div>
          </div>
          <div class="rp-tags-wrap" v-if="tape.tags.length">
            <span v-for="(tag, i) in tape.tags" :key="i" :class="['rp-tag', `rp-tag-${tag.强度}`]">
              {{ tag.名称 }}
            </span>
          </div>
        </div>
      </div>

      <!-- 初始化确认 -->
      <div v-if="resetTarget" class="delete-confirm">
        <div style="font-size: 11px; color: var(--text-primary); margin-bottom: 6px;">
          确定初始化磁带 <strong>{{ resetTarget }}</strong>？<br/>
          <span style="font-size: 10px; color: var(--text-muted);">将清空真实度、聚会履历、成长印记等所有数据</span>
        </div>
        <div class="btn-group">
          <button class="btn btn-danger" @click="executeReset">确认初始化</button>
          <button class="btn" @click="resetTarget = null">取消</button>
        </div>
      </div>

      <!-- 录入/编辑 -->
      <TapeForm
        v-if="showForm || editingTape"
        :edit-data="editingTape ?? undefined"
        @cancel="showForm = false; editingTape = null;"
        @saved="onTapeSaved"
      />
      <div v-else class="btn-group">
        <button class="btn btn-primary" @click="showForm = true">➕ 录入新会员</button>
        <button class="btn" @click="refreshTapes" title="从世界书刷新磁带列表">🔄</button>
      </div>
    </CollapsiblePanel>

    <!-- ═══ 照片管理 ═══ -->
    <CollapsiblePanel title="📸 照片库">
      <PhotoPanel @deleted="onPhotoDeleted" />
    </CollapsiblePanel>

    <!-- ═══ 俱乐部信息 ═══ -->
    <CollapsiblePanel title="🏛️ 俱乐部">
      <div class="grid-2col">
        <div class="info-row">
          <span class="k">聚会状态</span>
          <span class="v">{{ data.俱乐部.当前聚会.状态 }}</span>
        </div>
        <div class="info-row">
          <span class="k">照片总数</span>
          <span class="v">{{ data.俱乐部.照片计数 }}</span>
        </div>
        <div class="info-row">
          <span class="k">已录入磁带</span>
          <span class="v">{{ allTapes.length }}</span>
        </div>
        <div class="info-row">
          <span class="k">已插入磁带</span>
          <span class="v">{{ allTapes.filter(t => t.已插入).length }}</span>
        </div>
      </div>
    </CollapsiblePanel>
  </div>
</template>

<script setup lang="ts">
import CollapsiblePanel from './components/CollapsiblePanel.vue';
import PhotoPanel from './components/PhotoPanel.vue';
import ResourceBar from './components/ResourceBar.vue';
import StatusBadge from './components/StatusBadge.vue';
import type { RpTag } from './components/TapeForm.vue';
import TapeForm from './components/TapeForm.vue';
import { useDataStore } from './store';

const store = useDataStore();
const data = store.data;
const showForm = ref(false);
const editingTape = ref<{ 代号: string; content: string } | null>(null);
const resetTarget = ref<string | null>(null);

/** 所有磁带列表（从世界书扫描） */
interface TapeInfo {
  代号: string;
  已插入: boolean;
  tags: RpTag[];
}
const allTapes = ref<TapeInfo[]>([]);

/** 从世界书条目内容中提取字段值 */
function extractField(content: string, field: string): string {
  const m = content.match(new RegExp(`- ${field}:\\s*(.+)`, 'm'));
  return m?.[1]?.trim() ?? '';
}

/** 将世界书磁带字段导入到 MVU 变量 */
function importTapeToMVU(codename: string, content: string) {
  if (!data) return;
  if (!data.磁带索引[codename]) {
    data.磁带索引[codename] = {
      状态: '活跃', 真实度: 0,
      标记: '', 身体痕迹: '', 俱乐部人际: '',
      聚会履历草稿: '', 待同步照片: [], 同步版本: 0,
    };
  }
  const tape = data.磁带索引[codename];
  // 仅在首次导入时设置（不覆盖已有的 MVU 数据）
  if (!tape.标记) tape.标记 = extractField(content, '标记') || '[初来乍到]';
  if (!tape.身体痕迹) tape.身体痕迹 = extractField(content, '身体痕迹') || '无';
  if (!tape.俱乐部人际) tape.俱乐部人际 = extractField(content, '俱乐部人际') || '无';
  // 真实度从世界书导入
  const wb真实度 = parseFloat(extractField(content, '真实度'));
  if (!isNaN(wb真实度) && tape.真实度 === 0) tape.真实度 = wb真实度;
}

/** 从世界书扫描磁带列表并同步 MVU 索引 */
async function refreshTapes() {
  try {
    const entries = await getWorldbook('SecretClub-磁带库');
    const tapes: TapeInfo[] = [];

    for (const entry of entries) {
      const codename = entry.extra?.代号 ?? entry.name.replace('[磁带] ', '');
      if (entry.extra?.type !== '磁带') continue;

      // 解析 tags
      const parsedTags: RpTag[] = [];
      const tagMatch = entry.content.match(/-\s*角色扮演Tag:\s*(.+)/m);
      if (tagMatch) {
        const matches = tagMatch[1].matchAll(/(\S+?)\((轻微|中度|重度|核心)\)/g);
        for (const m of matches) {
          parsedTags.push({ 名称: m[1], 强度: m[2] as RpTag['强度'] });
        }
      }

      tapes.push({ 代号: codename, 已插入: entry.enabled, tags: parsedTags });

      // 同步到 MVU 索引：已插入的导入字段，未插入的移除
      if (data) {
        if (entry.enabled) {
          importTapeToMVU(codename, entry.content);
        } else {
          delete data.磁带索引[codename];
        }
      }
    }

    allTapes.value = tapes;
    console.info(`[SecretClub] 扫描到 ${tapes.length} 个磁带`);
  } catch {
    allTapes.value = [];
  }
}

/** 切换磁带插入/弹出 */
async function toggleTape(codename: string, insert: boolean) {
  try {
    await updateWorldbookWith('SecretClub-磁带库', (entries) => {
      for (const entry of entries) {
        if (entry.extra?.代号 === codename || entry.name === `[磁带] ${codename}`) {
          entry.enabled = insert;
        }
      }
      return entries;
    });

    // 更新 MVU 索引
    if (data) {
      if (insert) {
        // 找到对应条目并导入字段
        const entries = await getWorldbook('SecretClub-磁带库');
        const entry = entries.find(e => e.extra?.代号 === codename);
        if (entry) importTapeToMVU(codename, entry.content);
      } else {
        delete data.磁带索引[codename];
      }
    }

    // 更新本地列表
    const tape = allTapes.value.find(t => t.代号 === codename);
    if (tape) tape.已插入 = insert;

    toastr.success(insert ? `📥 磁带「${codename}」已插入` : `⏏️ 磁带「${codename}」已弹出`);
  } catch (e) {
    console.error('[SecretClub] 磁带切换失败:', e);
    toastr.error('磁带切换失败');
  }
}

/** 启动时自动扫描 */
onMounted(() => refreshTapes());

/** 新磁带保存后，更新 MVU 索引并刷新列表 */
function onTapeSaved(codename: string) {
  if (!data) return;
  if (!data.磁带索引[codename]) {
    data.磁带索引[codename] = {
      状态: '活跃', 真实度: 0,
      标记: '[初来乍到]', 身体痕迹: '无', 俱乐部人际: '无',
      聚会履历草稿: '', 待同步照片: [], 同步版本: 0,
    };
  }
  showForm.value = false;
  editingTape.value = null;
  refreshTapes();
}

/** 照片被删除后，更新照片计数 */
function onPhotoDeleted() {
  if (data && data.俱乐部.照片计数 > 0) {
    data.俱乐部.照片计数 -= 1;
  }
}

/** 初始化磁带：清空 MVU 变量 + 重置世界书条目 */
async function executeReset() {
  if (!data || !resetTarget.value) return;
  const codename = resetTarget.value;

  try {
    // 1. 重置 MVU 变量
    if (data.磁带索引[codename]) {
      data.磁带索引[codename] = {
        状态: '活跃', 真实度: 0,
        标记: '[初来乍到]', 身体痕迹: '无', 俱乐部人际: '无',
        聚会履历草稿: '', 待同步照片: [], 同步版本: 0,
      };
    }

    // 2. 重置世界书条目的履历和成长印记
    await updateWorldbookWith('SecretClub-磁带库', (entries) => {
      for (const entry of entries) {
        if (entry.extra?.代号 !== codename && entry.name !== `[磁带] ${codename}`) continue;

        // 重置聚会履历
        entry.content = entry.content.replace(
          /### 聚会履历[\s\S]*?(?=### 成长印记)/,
          '### 聚会履历\n（暂无）\n\n'
        );
        // 重置成长印记
        entry.content = entry.content
          .replace(/- 标记: .+/, '- 标记: [初来乍到]')
          .replace(/- 身体痕迹: .+/, '- 身体痕迹: 无')
          .replace(/- 俱乐部人际: .+/, '- 俱乐部人际: 无')
          .replace(/- 真实度: .+/, '- 真实度: 0');
      }
      return entries;
    });

    resetTarget.value = null;
    toastr.success(`磁带「${codename}」已初始化`);
    console.info(`[SecretClub] 磁带「${codename}」已初始化`);
  } catch (e) {
    console.error(`[SecretClub] 初始化磁带「${codename}」失败:`, e);
    toastr.error('初始化失败');
  }
}

/** 点击编辑按钮，从世界书加载内容并打开表单 */
async function startEdit(codename: string) {
  try {
    const entries = await getWorldbook('SecretClub-磁带库');
    const entry = entries.find(
      e => e.extra?.代号 === codename || e.name === `[磁带] ${codename}`
    );
    if (!entry) {
      toastr.error(`找不到磁带「${codename}」`);
      return;
    }
    showForm.value = false;
    editingTape.value = { 代号: codename, content: entry.content };
  } catch (e) {
    console.error('[SecretClub] 加载磁带失败:', e);
    toastr.error('加载磁带失败');
  }
}

/** 开始聚会 */
function startSession() {
  if (!data) return;
  const meetingNum = '#' + (data.俱乐部.照片计数 + 1);
  data.俱乐部.当前聚会.编号 = meetingNum;
  data.俱乐部.当前聚会.状态 = '进行中';
  data.俱乐部.当前聚会.开始楼层 = getLastMessageId();
  data.俱乐部.当前聚会.主题 = '';
  console.info(`[SecretClub] 聚会 ${meetingNum} 已开始，起始楼层: ${data.俱乐部.当前聚会.开始楼层}`);
}

/** 获取当前已插入(活跃)磁带的代号列表 */
function getActiveCodenames(): string[] {
  return allTapes.value.filter(t => t.已插入).map(t => t.代号);
}

/** 将单个磁带的 MVU 数据同步写回世界书 */
async function syncTape(codename: string) {
  if (!data) return;
  const tape = data.磁带索引[codename];
  if (!tape) {
    toastr.warning(`磁带「${codename}」未插入，无法同步`);
    return;
  }

  try {
    await updateWorldbookWith('SecretClub-磁带库', (entries) => {
      for (const entry of entries) {
        if (entry.extra?.代号 !== codename && entry.name !== `[磁带] ${codename}`) continue;

        // 1. 写回成长印记字段
        entry.content = entry.content
          .replace(/- 标记: .+/, `- 标记: ${tape.标记 || '[初来乍到]'}`)
          .replace(/- 身体痕迹: .+/, `- 身体痕迹: ${tape.身体痕迹 || '无'}`)
          .replace(/- 俱乐部人际: .+/, `- 俱乐部人际: ${tape.俱乐部人际 || '无'}`)
          .replace(/- 真实度: .+/, `- 真实度: ${tape.真实度}`);

        // 2. 追加聚会履历草稿
        if (tape.聚会履历草稿.trim()) {
          const draft = tape.聚会履历草稿.trim();
          if (entry.content.includes('（暂无）')) {
            entry.content = entry.content.replace('（暂无）', draft);
          } else {
            const pos = entry.content.indexOf('### 成长印记');
            if (pos >= 0) {
              entry.content = entry.content.slice(0, pos) + draft + '\n\n' + entry.content.slice(pos);
            } else {
              entry.content += '\n' + draft;
            }
          }
        }
      }
      return entries;
    });

    // 清空草稿和待同步队列
    tape.聚会履历草稿 = '';
    tape.待同步照片 = [];
    tape.同步版本 += 1;
    toastr.success(`🔄 磁带「${codename}」已同步 (v${tape.同步版本})`);
    console.info(`[SecretClub] 磁带「${codename}」同步完成`);
  } catch (e) {
    console.error(`[SecretClub] 同步磁带「${codename}」失败:`, e);
    toastr.error(`同步「${codename}」失败`);
  }
}

/** 同步所有已插入的磁带 */
async function syncAllTapes() {
  if (!data) return;
  const codenames = getActiveCodenames();
  let count = 0;
  for (const codename of codenames) {
    const tape = data.磁带索引[codename];
    if (!tape) continue;
    // 只同步有变化的磁带
    if (tape.聚会履历草稿.trim() || tape.待同步照片.length) {
      await syncTape(codename);
      count++;
    }
  }
  if (count === 0) {
    toastr.info('没有需要同步的数据');
  } else {
    toastr.success(`🔄 已同步 ${count} 个磁带`);
  }
}

const isProcessing = ref(false);

/**
 * 从 AI 返回的原始文本中提取 JSON 对象。
 * 处理多种格式：纯 JSON、markdown代码块包裹、前后有文本干扰等。
 */
function extractJSON(raw: string): any | null {
  // 1) 先尝试从 markdown 代码块中提取
  const codeBlockMatch = raw.match(/```(?:json)?\s*\n?([\s\S]*?)\n?```/);
  const text = codeBlockMatch ? codeBlockMatch[1].trim() : raw;

  // 2) 找到第一个 { 和对应的 }
  const start = text.indexOf('{');
  if (start < 0) return null;

  let depth = 0;
  let end = -1;
  for (let i = start; i < text.length; i++) {
    if (text[i] === '{') depth++;
    else if (text[i] === '}') {
      depth--;
      if (depth === 0) { end = i; break; }
    }
  }
  if (end < 0) return null;

  try {
    return JSON.parse(text.slice(start, end + 1));
  } catch (e) {
    console.error('[SecretClub] JSON 解析失败:', e, '\n原始文本片段:', text.slice(start, end + 1).substring(0, 200));
    return null;
  }
}

/** 从 AI 回复中提取指定 XML 标签内的 JSON */
function extractTagJSON(result: string, tagName: string): any | null {
  const regex = new RegExp(`<${tagName}>([\\s\\S]*?)</${tagName}>`);
  const match = result.match(regex);
  if (!match) return null;
  return extractJSON(match[1]);
}

/** 拍照 — 通过聊天框生成 */
async function takePhoto() {
  if (!data || isProcessing.value) return;
  isProcessing.value = true;

  const activeTapes = getActiveCodenames();
  const meetingDate = new Date().toLocaleDateString('zh-CN');

  try {
    const result = await generate({
      user_input: `📷 拍照！记录下这一刻的场景。`,
      injects: [{
        role: 'system',
        content: `【附加任务 — 拍照】
用户请求了“拍照”。在本次回复的正文中，请用200字左右的生动文字描写当前场景的“照片画面”——仿佛摄影师按下快门，用文学性的语言还原这一瞬间。

然后在回复末尾，用以下XML标签包裹结构化数据（这部分会被前端隐藏）：

<PhotoData>
{"简述":"一句话概括照片画面，不超过30字","详述":"详细场景描述","参与人物":["代号"]}
</PhotoData>

当前在场角色代号：${activeTapes.join('、') || '无'}
参与人物只能从以上代号中选取。`,
        position: 'in_chat',
        depth: 0,
        should_scan: false,
      }],
    });

    console.info('[SecretClub] 拍照返回:', result);

    const photo = extractTagJSON(result, 'PhotoData');
    if (!photo || !photo.简述) {
      console.warn('[SecretClub] 照片数据提取失败，跳过写入');
      toastr.warning('照片已生成但数据解析失败，无法存档');
      isProcessing.value = false;
      return;
    }

    const photoId = `P-${String(data.俱乐部.照片计数 + 1).padStart(4, '0')}`;
    const participants: string[] = photo.参与人物 ?? [];

    // ═══ 保存照片到磁带库世界书（与磁带同库，type 区分） ═══
    await createWorldbookEntries('SecretClub-磁带库', [{
      name: `[照片] ${photoId}【${meetingDate}】【${participants.join('/')}】`,
      enabled: false,
      content: [
        `照片编号: ${photoId}`,
        `拍摄时间: ${meetingDate}`,
        `参与人物: ${participants.join('、')}`,
        `照片简述: ${photo.简述}`,
        `照片详述: ${photo.详述}`,
      ].join('\n'),
      strategy: {
        type: 'selective',
        keys: [photoId],
        keys_secondary: { logic: 'and_any', keys: [] },
        scan_depth: 'same_as_global',
      },
      position: { type: 'before_character_definition', role: 'system', depth: 0, order: 200 },
      recursion: { prevent_incoming: false, prevent_outgoing: true, delay_until: null },
      extra: { type: '照片', photoId, participants, meetingDate },
    }]);

    // ═══ 照片引用写入 MVU（可回滚），不直接写世界书 ═══
    for (const codename of participants) {
      const tape = data.磁带索引[codename];
      if (!tape) continue;
      tape.待同步照片.push(photoId);
      tape.聚会履历草稿 += `\n- [${meetingDate}] 📷 照片 ${photoId}：${photo.简述}`;
    }

    data.俱乐部.照片计数 += 1;
    toastr.success(`📷 拍照完成：${photo.简述}（数据待同步）`);
    console.info(`[SecretClub] 照片 ${photoId} 已保存，已写回 ${participants.length} 个磁带`);
  } catch (e) {
    console.error('[SecretClub] 拍照失败:', e);
    toastr.error('拍照失败，请检查控制台');
  } finally {
    isProcessing.value = false;
  }
}

/** 结束聚会 — 通过聊天框生成 */
async function endSession() {
  if (!data || isProcessing.value) return;
  isProcessing.value = true;

  const activeTapes = getActiveCodenames();
  const meetingDate = new Date().toLocaleDateString('zh-CN');
  const meetingNum = data.俱乐部.当前聚会.编号;

  toastr.info('🔚 正在结束聚会...');

  try {
    const result = await generate({
      user_input: `🔚 本次聚会结束。请总结本次聚会经历。`,
      injects: [{
        role: 'system',
        content: `【附加任务 — 聚会结束总结】
用户宣布本次聚会（编号 ${meetingNum}）结束。在本次回复中，请完成两件事：

1. 正文：写200-300字的聚会结束场景描写，描述活动结束到会员陆续离开的氛围。

2. 在回复末尾，用XML标签包裹每位角色的总结数据（前端会隐藏此部分）：

<SessionData>
{"角色总结":{
  "代号":{
    "摘要":"一句话概括",
    "获得标记":["标记"],
    "身体痕迹":"",
    "人际变化":{}
  }
}}
</SessionData>

参与角色代号：${activeTapes.join('、') || '无'}
请为每位参与角色都生成总结。`,
        position: 'in_chat',
        depth: 0,
        should_scan: false,
      }],
    });

    console.info('[SecretClub] 聚会总结返回:', result);

    const summary = extractTagJSON(result, 'SessionData');
    if (!summary) {
      console.warn('[SecretClub] 聚会总结数据提取失败，跳过写入');
      toastr.warning('聚会已结束，但总结数据解析失败');
    } else {
      const 角色总结 = summary.角色总结 ?? summary;

      // ═══ 对每个角色写入 MVU（可回滚） ═══
      for (const [codename, charSummary] of Object.entries(角色总结) as [string, any][]) {
        const tape = data.磁带索引[codename];
        if (!tape) continue;

        // 追加履历草稿
        const historyRecord = [
          `- [${meetingDate}] 聚会${meetingNum}：${charSummary.摘要 ?? '（无摘要）'}`,
          charSummary.获得标记?.length ? `  标记: ${charSummary.获得标记.map((t: string) => `[${t}]`).join('')}` : null,
          charSummary.身体痕迹 ? `  痕迹: ${charSummary.身体痕迹}` : null,
        ].filter(Boolean).join('\n');
        tape.聚会履历草稿 += '\n' + historyRecord;

        // 更新标记
        if (charSummary.获得标记?.length) {
          tape.标记 += charSummary.获得标记.map((t: string) => `[${t}]`).join('');
        }
        // 更新痕迹
        if (charSummary.身体痕迹) {
          tape.身体痕迹 = charSummary.身体痕迹;
        }
        // 更新人际
        if (charSummary.人际变化 && Object.keys(charSummary.人际变化).length) {
          const relStr = Object.entries(charSummary.人际变化).map(([k, v]) => `${k}(${v})`).join('、');
          tape.俱乐部人际 = tape.俱乐部人际 === '无' ? relStr : tape.俱乐部人际 + '、' + relStr;
        }

        console.info(`[SecretClub] 磁带「${codename}」MVU 已更新（待同步）`);
      }

      toastr.success(`🔚 聚会${meetingNum}已结束，${Object.keys(角色总结).length} 个角色数据已更新（待同步）`);
    }
  } catch (e) {
    console.error('[SecretClub] 聚会总结失败:', e);
    toastr.warning('聚会已结束，但总结生成失败');
  } finally {
    data.俱乐部.当前聚会.状态 = '未开始';
    data.俱乐部.当前聚会.编号 = '';
    data.俱乐部.当前聚会.主题 = '';
    isProcessing.value = false;
    refreshTapes();
  }
}
</script>

