<template>
  <div class="photo-panel">
    <div v-if="loading" style="color: var(--text-muted); font-size: 11px;">加载中...</div>
    <div v-else-if="!photos.length" style="color: var(--text-muted); font-size: 11px;">
      暂无照片。在聚会中点击「📷 拍照」来记录场景。
    </div>

    <div v-for="photo in photos" :key="photo.photoId" class="photo-card">
      <div class="photo-header">
        <span class="photo-id">{{ photo.photoId }}</span>
        <span class="photo-date">{{ photo.meetingDate }}</span>
      </div>
      <div class="photo-summary">{{ photo.简述 }}</div>
      <div class="photo-participants" v-if="photo.participants.length">
        <span class="rp-tag rp-tag-中度" v-for="p in photo.participants" :key="p">{{ p }}</span>
      </div>

      <!-- 展开详情 -->
      <details class="photo-details">
        <summary>📖 查看详述</summary>
        <div class="photo-detail-text">{{ photo.详述 }}</div>
      </details>

      <button class="btn-delete" @click="confirmDelete(photo)" :disabled="deleting">
        🗑️ 删除
      </button>
    </div>

    <!-- 删除确认 -->
    <div v-if="deleteTarget" class="delete-confirm">
      <div class="delete-confirm-text">
        确定删除照片 <strong>{{ deleteTarget.photoId }}</strong>？<br/>
        <span style="font-size: 10px; color: var(--text-muted);">将同时清理磁带履历中的引用</span>
      </div>
      <div class="btn-group">
        <button class="btn btn-danger" @click="executeDelete" :disabled="deleting">
          {{ deleting ? '删除中...' : '确认删除' }}
        </button>
        <button class="btn" @click="deleteTarget = null" :disabled="deleting">取消</button>
      </div>
    </div>

    <div class="btn-group" v-if="photos.length">
      <button class="btn" @click="loadPhotos" title="刷新照片列表">🔄 刷新</button>
    </div>
  </div>
</template>

<script setup lang="ts">
interface PhotoInfo {
  photoId: string;
  meetingDate: string;
  participants: string[];
  简述: string;
  详述: string;
  entryName: string;
}

const emit = defineEmits<{
  deleted: [];
}>();

const photos = ref<PhotoInfo[]>([]);
const loading = ref(false);
const deleteTarget = ref<PhotoInfo | null>(null);
const deleting = ref(false);

/** 从世界书加载所有照片 */
async function loadPhotos() {
  loading.value = true;
  try {
    const entries = await getWorldbook('SecretClub-磁带库');
    const list: PhotoInfo[] = [];

    for (const entry of entries) {
      if (entry.extra?.type !== '照片') continue;
      list.push({
        photoId: entry.extra.photoId ?? '?',
        meetingDate: entry.extra.meetingDate ?? '?',
        participants: entry.extra.participants ?? [],
        简述: extractField(entry.content, '照片简述'),
        详述: extractField(entry.content, '照片详述'),
        entryName: entry.name,
      });
    }

    // 按 photoId 倒序排列（最新在前）
    list.sort((a, b) => b.photoId.localeCompare(a.photoId));
    photos.value = list;
  } catch {
    photos.value = [];
  } finally {
    loading.value = false;
  }
}

function extractField(content: string, field: string): string {
  const m = content.match(new RegExp(`${field}:\\s*(.+)`, 'm'));
  return m?.[1]?.trim() ?? '';
}

function confirmDelete(photo: PhotoInfo) {
  deleteTarget.value = photo;
}

/** 执行删除：移除照片条目 + 清理磁带履历引用 */
async function executeDelete() {
  if (!deleteTarget.value) return;
  deleting.value = true;
  const photoId = deleteTarget.value.photoId;

  try {
    // 从磁带库中删除照片条目 + 清理磁带履历引用（单次更新）
    await updateWorldbookWith('SecretClub-磁带库', (entries) => {
      const result = entries.filter(e => e.extra?.photoId !== photoId);
      for (const entry of result) {
        if (entry.extra?.type !== '磁带') continue;
        const lines = entry.content.split('\n');
        entry.content = lines.filter(line => !line.includes(photoId)).join('\n');
      }
      return result;
    });

    photos.value = photos.value.filter(p => p.photoId !== photoId);
    deleteTarget.value = null;
    toastr.success(`🗑️ 照片 ${photoId} 已删除`);
    emit('deleted');
  } catch (e) {
    console.error('[SecretClub] 删除照片失败:', e);
    toastr.error('删除失败，请检查控制台');
  } finally {
    deleting.value = false;
  }
}

onMounted(() => loadPhotos());
</script>

<style scoped>
.photo-panel {
  padding: 4px 0;
}
.photo-card {
  background: var(--bg-secondary);
  border: 1px solid var(--border);
  border-radius: 6px;
  padding: 8px 10px;
  margin-bottom: 5px;
  transition: border-color 0.2s;
}
.photo-card:hover {
  border-color: var(--accent-fuchsia);
}
.photo-header {
  display: flex;
  justify-content: space-between;
  align-items: center;
  margin-bottom: 4px;
}
.photo-id {
  font-size: 11px;
  font-weight: 700;
  color: var(--accent-fuchsia);
  font-family: monospace;
}
.photo-date {
  font-size: 10px;
  color: var(--text-muted);
}
.photo-summary {
  font-size: 12px;
  color: var(--text-primary);
  margin-bottom: 4px;
  line-height: 1.4;
}
.photo-participants {
  display: flex;
  flex-wrap: wrap;
  gap: 2px;
  margin-bottom: 4px;
}
.photo-details {
  margin: 4px 0;
}
.photo-details summary {
  font-size: 10px;
  color: var(--text-muted);
  cursor: pointer;
  user-select: none;
}
.photo-details summary:hover {
  color: var(--accent-violet);
}
.photo-detail-text {
  font-size: 11px;
  color: var(--text-secondary);
  line-height: 1.5;
  padding: 6px 8px;
  margin-top: 4px;
  background: var(--bg-tertiary);
  border-radius: 4px;
  white-space: pre-wrap;
}
.btn-delete {
  background: none;
  border: none;
  color: var(--text-muted);
  font-size: 10px;
  cursor: pointer;
  padding: 2px 4px;
  transition: color 0.15s;
}
.btn-delete:hover {
  color: var(--accent-rose);
}
.delete-confirm {
  background: rgba(251, 113, 133, 0.08);
  border: 1px solid rgba(251, 113, 133, 0.3);
  border-radius: 6px;
  padding: 8px 10px;
  margin: 6px 0;
}
.delete-confirm-text {
  font-size: 11px;
  color: var(--text-primary);
  margin-bottom: 6px;
}
</style>
