<template>
  <div class="panel">
    <div class="panel-header" @click="toggle">
      <span>{{ title }}</span>
      <span class="toggle" :class="{ 'toggle-open': open }">▶</span>
    </div>
    <div class="panel-body-wrap" ref="bodyRef" :style="bodyStyle">
      <div class="panel-body">
        <slot />
      </div>
    </div>
  </div>
</template>

<script setup lang="ts">
const props = defineProps<{ title: string; defaultOpen?: boolean }>();
const open = ref(props.defaultOpen ?? false);
const bodyRef = ref<HTMLElement>();

const bodyStyle = computed(() => {
  if (!open.value) return { maxHeight: '0px', opacity: '0', overflow: 'hidden' };
  return { maxHeight: '2000px', opacity: '1', overflow: 'visible' };
});

function toggle() {
  open.value = !open.value;
}
</script>

<style scoped>
.panel-body-wrap {
  transition: max-height 0.35s cubic-bezier(0.4, 0, 0.2, 1), opacity 0.25s ease;
}
.toggle {
  display: inline-block;
  transition: transform 0.25s ease;
}
.toggle-open {
  transform: rotate(90deg);
}
</style>
